content.text:
`XMLHttpRequest` AJAX sorğuları yaratmaq üçün klassik bir üsuldur.
Sintaksis:
```javascript
const xhr = new XMLHttpRequest();
xhr.open(method, url, async);
xhr.send();
```
- `method`: HTTP metodu (`GET`, `POST` və s.).
- `url`: Sorğunun göndərildiyi ünvan.
- `async`: Sorğunun asinxron olub-olmaması (adətən `true`).

content.code:
// XMLHttpRequest nümunəsi
const xhr = new XMLHttpRequest();
xhr.open('GET', 'https://jsonplaceholder.typicode.com/posts/1', true);
xhr.onload = function() {
  if (xhr.status === 200) {
    const data = JSON.parse(xhr.responseText);
    console.log('Məlumat:', data);
  } else {
    console.log('Xəta:', xhr.status);
  }
};
xhr.send();

// fetch nümunəsi
fetch('https://jsonplaceholder.typicode.com/posts/1')
  .then(response => {
    if (!response.ok) throw new Error('Xəta: ' + response.status);
    return response.json();
  })
  .then(data => console.log('Məlumat:', data))
  .catch(error => console.log('Xəta:', error));

// Hadisə ilə fetch nümunəsi
const button = document.querySelector('#myButton');
button.addEventListener('click', () => {
  fetch('https://jsonplaceholder.typicode.com/posts/1')
    .then(response => response.json())
    .then(data => {
      const container = document.querySelector('#myContainer');
      container.innerText = data.title;
      console.log('Məlumat yükləndi:', data);
    })
    .catch(error => console.log('Xəta:', error));
});

// Səhvə yol açan nümunə
fetch('https://nonexistent.api/data')
  .then(response => response.json())
  .then(data => console.log(data)) // Xəta: Şəbəkə xətası və ya yanlış URL

// Düzgün yol
fetch('https://jsonplaceholder.typicode.com/posts/1')
  .then(response => {
    if (!response.ok) throw new Error('Xəta: ' + response.status);
    return response.json();
  })
  .then(data => console.log('Məlumat:', data))
  .catch(error => console.log('Xəta:', error));

content.text:
`XMLHttpRequest` is a classic method for creating AJAX requests.
Syntax:
```javascript
const xhr = new XMLHttpRequest();
xhr.open(method, url, async);
xhr.send();
```
- `method`: HTTP method (`GET`, `POST`, etc.).
- `url`: The request destination.
- `async`: Whether the request is asynchronous (usually `true`).

content.code:
// XMLHttpRequest example
const xhr = new XMLHttpRequest();
xhr.open('GET', 'https://jsonplaceholder.typicode.com/posts/1', true);
xhr.onload = function() {
  if (xhr.status === 200) {
    const data = JSON.parse(xhr.responseText);
    console.log('Data:', data);
  } else {
    console.log('Error:', xhr.status);
  }
};
xhr.send();

// fetch example
fetch('https://jsonplaceholder.typicode.com/posts/1')
  .then(response => {
    if (!response.ok) throw new Error('Error: ' + response.status);
    return response.json();
  })
  .then(data => console.log('Data:', data))
  .catch(error => console.log('Error:', error));

// Event-driven fetch example
const button = document.querySelector('#myButton');
button.addEventListener('click', () => {
  fetch('https://jsonplaceholder.typicode.com/posts/1')
    .then(response => response.json())
    .then(data => {
      const container = document.querySelector('#myContainer');
      container.innerText = data.title;
      console.log('Data loaded:', data);
    })
    .catch(error => console.log('Error:', error));
});

// Error-prone example
fetch('https://nonexistent.api/data')
  .then(response => response.json())
  .then(data => console.log(data)) // Error: Network error or invalid URL

// Correct approach
fetch('https://jsonplaceholder.typicode.com/posts/1')
  .then(response => {
    if (!response.ok) throw new Error('Error: ' + response.status);
    return response.json();
  })
  .then(data => console.log('Data:', data))
  .catch(error => console.log('Error:', error));

