`XMLHttpRequest` — это классический способ создания AJAX-запросов.
Синтаксис:
```javascript
const xhr = new XMLHttpRequest();
xhr.open(method, url, async);
xhr.send();
```
- `method`: HTTP-метод (`GET`, `POST` и т.д.).
- `url`: Адрес, на который отправляется запрос.
- `async`: Асинхронный ли запрос (обычно `true`).

content.code:
// Пример XMLHttpRequest
const xhr = new XMLHttpRequest();
xhr.open('GET', 'https://jsonplaceholder.typicode.com/posts/1', true);
xhr.onload = function() {
  if (xhr.status === 200) {
    const data = JSON.parse(xhr.responseText);
    console.log('Данные:', data);
  } else {
    console.log('Ошибка:', xhr.status);
  }
};
xhr.send();

// Пример fetch
fetch('https://jsonplaceholder.typicode.com/posts/1')
  .then(response => {
    if (!response.ok) throw new Error('Ошибка: ' + response.status);
    return response.json();
  })
  .then(data => console.log('Данные:', data))
  .catch(error => console.log('Ошибка:', error));

// Пример fetch с событием
const button = document.querySelector('#myButton');
button.addEventListener('click', () => {
  fetch('https://jsonplaceholder.typicode.com/posts/1')
    .then(response => response.json())
    .then(data => {
      const container = document.querySelector('#myContainer');
      container.innerText = data.title;
      console.log('Данные загружены:', data);
    })
    .catch(error => console.log('Ошибка:', error));
});

// Пример с ошибкой
fetch('https://nonexistent.api/data')
  .then(response => response.json())
  .then(data => console.log(data)) // Ошибка: Сетевая ошибка или неверный URL

// Правильный подход
fetch('https://jsonplaceholder.typicode.com/posts/1')
  .then(response => {
    if (!response.ok) throw new Error('Ошибка: ' + response.status);
    return response.json();
  })
  .then(data => console.log('Данные:', data))
  .catch(error => console.log('Ошибка:', error));
